import{j as t,b as o,c as r,a9 as l}from"./chunks/framework.CFGK5tmi.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"front/1. 以终为始，用JD去写你的简历专业技能.md","filePath":"front/1. 以终为始，用JD去写你的简历专业技能.md","lastUpdated":null}'),p={name:"front/1. 以终为始，用JD去写你的简历专业技能.md"},i=l('<p><a href="https://articles.zsxq.com/id_x4esh7nnukh7.html" target="_blank" rel="noreferrer">https://articles.zsxq.com/id_x4esh7nnukh7.html</a></p><p><strong>1. 以终为始，用JD去写你的简历专业技能</strong></p><p>前端的专业技能怎么写，我觉得最好的办法是根据招聘网站上的jd去写，校招生的要求就是基础布局（html/css） + JS核心概念清楚 + 框架 + 一定的项目经验 + 计算机基础（主要是计算机网络和算法），这几个可以各占据一行作为专业技能嘛</p><p>所以你完全可以根据JD去决定你要学什么，简历上的专业技能写什么</p><p>------------------</p><p>注：下面的链接是一个校招简历修改的过程，内含广告，请注意辨别</p><p><a href="https://mp.weixin.qq.com/s/Nd_U9hB5uRlCdMyxWpBVBQ" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/Nd_U9hB5uRlCdMyxWpBVBQ</a></p><p><strong>2. 面试的本质就是考试</strong></p><p>面试是一种考试，你只要把知识点掌握，然后合理的表达即可</p><p><strong>HTML</strong></p><p><strong>1. html语义化标签（对语义化的理解）</strong></p><ol start="2"><li>文档声明的作用？</li><li>meta标签</li></ol><p><strong>4. html5新特性</strong></p><ol start="5"><li>src和href的区别？</li></ol><p><strong>6. 行内元素，块级元素的区别？</strong></p><ol start="7"><li>link和@import导入样式的区别？</li><li>常用的图片格式和应用场景</li><li>常见的浏览器内核</li><li>srcipt中defer和async的区别？</li><li>需要注意哪些SEO</li></ol><p><strong>CSS</strong></p><p><strong>1. css选择器</strong></p><p><strong>2. css选择器权重</strong></p><p><strong>3. 盒子模型（标准盒子模型和怪异盒子模型）</strong></p><ol start="4"><li>margin塌陷和margin重叠现象</li></ol><p><strong>5. 如何清除浮动</strong></p><ol start="6"><li>css定位属性position（文档流）</li></ol><p><strong>7. flex布局（grid布局） （必问，可以看阮一峰老师的那篇文档）</strong></p><ol start="8"><li>css单位的区别？(px, em, rem, vw, vh)</li></ol><p>9: display相关属性</p><p><strong>10: BFC(高频)</strong></p><ol start="11"><li>常见布局方式 【 重点 】</li></ol><p><strong>- 居中的实现方式（必问）</strong></p><p>- 三栏布局：圣杯布局和双飞翼布局</p><p>- css画三角形</p><ol start="12"><li>媒体查询</li></ol><p><strong>13. 移动端响应式布局方式</strong></p><ol start="14"><li>less和scss/sass的基本使用</li></ol><p><strong>15. 回流和重绘</strong></p><ol start="16"><li>z-index压盖顺序</li><li>过渡与动画</li><li>伪类和伪元素的区别</li><li>before和after双冒号和单冒号有什么区别？</li></ol><p><strong>20：css3新增了哪些特性？</strong></p><p>21: css雪碧图的作用？</p><p>22: display:none和visibility:hidden、opacity: 0的区别</p><p>23: opacity和rgba区别</p><p>24: line-height如何继承？</p><ol start="25"><li>如何脱离文档流</li></ol><p>26: 怎么让chrome支持12px以下的文字</p><ol start="27"><li>怎么画宽度为0.5px的线</li></ol><p><strong>Javascript(全都是重点）</strong></p><ol><li>数据类型（原始数据类型和引用数据类型，堆栈内存），数据类型检测和数据类型转换</li><li>数组常用方法、对象常用方法</li><li>类数组和数组的区别和转换，数组的检测方式，数组去重和排序</li><li>函数执行机制和执行上下文，执行上下文栈（普通函数，立即执行函数，箭头函数、构造函数）</li><li>闭包作用域（变量提升，arguments, 作用域与作用域链，闭包的应用场景，闭包优缺点）</li><li>内存泄漏和垃圾回收机制</li><li>this指向的规则（call/bind/apply的使用)</li><li>new和构造函数</li><li>原型与原型链的理解</li><li>继承实现的方式和区别？</li><li>深拷贝与浅拷贝</li><li>事件循环机制（任务队列，微任务，宏任务，同步，异步，进程和线程，浏览器线程）</li><li>JS异步解决方案（回调函数、Promise、Generator、async、定时器）</li><li>DOM选择器</li><li>常见DOM操作（增，删，改）</li><li>事件流的过程（事件冒泡和事件捕获）、事件处理程序（DOM0级事件处理程序和DOM2级事件处理程序）、事件对象、事件委托</li></ol><p><strong>ES6</strong></p><p><strong>1. let、const、var的区别</strong></p><ol start="2"><li>块级作用域</li><li>暂时性死区</li><li>解构赋值</li></ol><p><strong>5. 箭头函数和普通函数的区别（this的指向）</strong></p><p><strong>6. Symbol概念和作用</strong></p><p>--------------------</p><p>下面几个的要求可以适当放松</p><ol start="7"><li>Set和Map数据结构</li><li>WeaSet和WeakMap</li><li>Proxy</li><li>Reflect对象</li></ol><p>--------------------</p><p><strong>10.Promise（Promise的链式调用，Promise的状态、Promise的方法）【必考】</strong></p><p>11.Generator及其异步方面的应用</p><p>12.async函数和await</p><p><strong>13. class基本语法及继承</strong></p><p><strong>14. 模块加载方案比较（CommonJS和ES6的Module）</strong></p><ol start="15"><li>Iterator和for...of（Iterator遍历器的实现）</li></ol><p><strong>js具体面试题补充</strong></p><ol><li>addEventListener和onClick()的区别</li><li>new和Object.create()的区别</li><li>DOM的location对象</li></ol><p><strong>4. Object.defineProperty()的使用</strong></p><ol start="5"><li>Array.sort()方法与实现机制</li></ol><p><strong>6. 函数柯里化、组合函数</strong></p><ol start="7"><li>BOM属性对象方法（scroll/client/offset)</li></ol><p><strong>8. null和undefined的区别</strong></p><p><strong>9. ==数据类型转换的规则</strong></p><ol start="10"><li>数组高阶函数、some、every、filter、map、reduce</li><li>mouseenter和mouseover的区别？</li></ol><p><strong>12. 伪数组转为数组的方式</strong></p><p><strong>13. 遍历对象属性的方法</strong></p><p>判断是否是对象的私有属性：obj.hasOwnProperty()</p><p>获取对象的所有实例属性和函数，不包含原型链继承的属性和函数 Object.getOwnPropertyNames()</p><p>获取对象可枚举的属性，不包含继承属性 Object.keys()</p><ol start="14"><li>合并数组的方法</li><li>document和window的区别</li><li>Object.is和===的区别</li><li>isNaN和Number.isNaN()的区别？</li><li>0.1 + 0.2 !== 0.3</li></ol><p><strong>19. 判断一个变量是数组还是对象</strong></p><ol start="20"><li>属性访问时点操作符和[]中括号操作符的区别</li><li>严格模式</li><li>扩展运算符与rest运算符的区别</li></ol><p><strong>23. Object.assign()</strong></p><p><strong>24. Map和普通对象、WeakMap的区别？</strong></p><p><strong>25. 循环语法比较及使用场景（for、forEach、map的区别/ for...in、for...of的区别）</strong></p><ol start="26"><li>forEach可以中断吗</li><li>forEach和map方法的区别?</li></ol><p><strong>28. e.target和e.currentTarget的区别？</strong></p><ol start="29"><li>阻止事件冒泡event.stopPropagation()</li><li>event.stopPropagation()和stopImmediatePropagation()</li><li>HTMLCollection和NodeList的区别？</li></ol><p><strong>Ajax</strong></p><p><strong>1. Ajax的请求过程(手写ajax)</strong></p><ol start="2"><li>POST请求格式</li></ol><p><strong>3. 跨域、同源策略及跨域实现方式和原理</strong></p><ol start="4"><li>JSONP, CORS</li><li>JSON序列化和反序列化</li><li>Axios的使用</li><li>Ajax和Fetch,Axios有什么区别</li></ol><p><strong>手写</strong></p><p><strong>1. new 【高频 】</strong></p><p><strong>2. call/bind/apply</strong></p><p><strong>3. Promise.all 【 大厂高频 】</strong></p><p><strong>4. instanceof</strong></p><p><strong>5. 柯里化函数，组合函数</strong></p><p><strong>6. 防抖和节流【必考】</strong></p><p><strong>7. Ajax [必考]</strong></p><p><strong>8. 深拷贝与浅拷贝【必考】</strong></p><p><strong>9. 继承 【必考】</strong></p><p><strong>10. 数组去重，数组排序 [小公司必会]</strong></p><ol start="11"><li>数组扁平化</li><li>字符串中出现最多次数的字符</li><li>字符串反转</li><li>字符串驼峰转换</li><li>实现trim过滤字符串空格</li><li>事件委托</li><li>解析url中的key</li><li>正则匹配手机号</li></ol><p><strong>Vue</strong></p><p><strong>1. vue生命周期(父子组件)</strong></p><p>created和mounted的区别</p><p>在那个生命周期中获取数据</p><ol start="2"><li>computed/methods/watch的区别</li></ol><p><strong>3. v-show和v-if的区别</strong></p><p><strong>4. v-if和v-for优先级</strong></p><p><strong>5. v-for为什么要用key</strong></p><p><strong>6. 组件通信</strong></p><ol start="7"><li>插槽的使用</li></ol><p><strong>8. nextTick的使用和原理</strong></p><ol start="9"><li>常用的指令</li><li>scoped的作用</li><li>常用的修饰符</li></ol><p>**12. keep-alive的作用？**keep-alive中的生命周期钩子</p><ol start="13"><li>vue如何监听对象或者数组属性的变化</li></ol><p>------------</p><ol><li>说说你对vue的理解？</li><li>v-model的实现原理</li></ol><p><strong>3. 双向数据绑定的原理</strong></p><p><strong>4. MVVM和MVC的区别？</strong></p><p><strong>5. 虚拟DOM和diff算法</strong></p><p>-------------</p><ol><li>Proxy和defineProperty的区别</li><li>Vue3.0为什么要使用proxy</li><li>Composition API</li></ol><p>---------------</p><ol><li>hash和history模式的区别？</li><li>SPA单页面应用的优缺点</li><li>params和query传递参数的区别</li><li>路由钩子函数/路由守卫</li><li>路由懒加载</li><li>router和route的区别</li><li>编程式导航和声明式导航</li></ol><p>--------------------</p><p><strong>1. vuex的作用？</strong></p><p><strong>2. state/mutation/action/getter/module的作用</strong></p><p><strong>3. mutation和action的区别？</strong></p><p><strong>React</strong></p><blockquote><p>React我刚学没多久，下面只提供一些重点</p></blockquote><ol><li>生命周期</li><li>类组件和函数式组件的区别</li><li>setState是同步更新还是异步更新</li><li>高阶组件</li><li>虚拟DOM和diff算法</li><li>key的作用</li><li>React Hook</li><li>Redux工作流程</li></ol><p><strong>Webpack</strong></p><p><strong>1. webpack的基础配置和基本概念</strong></p><p><strong>2. loader和plugin的不同</strong></p><p><strong>3. 常用的loader和plugin?</strong></p><p><strong>4. webpack的proxy配置解决跨域问题</strong></p><p><strong>网络/浏览器</strong></p><ol><li>TCP/IP网络分层</li></ol><p><strong>2. tcp和udp的区别和使用场景</strong></p><p><strong>3. 三次握手和四次挥手</strong></p><ol start="4"><li>HTTP请求方法</li></ol><p><strong>5. GET和POST的区别</strong></p><ol start="6"><li>HTTP请求报文和响应报文、请求头和响应头</li></ol><p><strong>7. HTTP状态码 【 高频 】</strong></p><p><strong>8. HTTP缓存 【 高频 】</strong></p><p><strong>9. HTTP1.0/1.1/2.0/3.0之间的区别？</strong></p><p><strong>10.HTTPS和HTTP之间的区别？</strong></p><p>对称加密和非对称加密</p><p>11.对Keep-Alive的理解</p><p>12.DNS查询过程</p><p><strong>13.CDN</strong></p><p>--------------------</p><ol><li>XSS攻击及防御</li><li>CSRF攻击及防御</li></ol><p>--------------------</p><p><strong>1. 浏览器页面渲染过程</strong></p><p><strong>2. 浏览器缓存 （强缓存和协商缓存）</strong></p><p><strong>3. 浏览器存储</strong></p><p><strong>localStorage、sessionStorage、cookie之间的区别？</strong></p><p><strong>4. 从url输入到界面展示，发生了什么？</strong></p><p><strong>5. 重排和重绘</strong></p><ol start="6"><li>浏览器进程</li><li>浏览器同源策略</li></ol><p>---------------------</p><p><strong>1. 进程和线程之间的区别</strong></p><ol start="2"><li>进程通信</li><li>死锁</li></ol><p><strong>其他</strong></p><p><strong>1. 项目性能优化方案</strong></p><p>CDN</p><p>懒加载</p><p>防抖和节流</p><p>回流与重绘</p><p>图片优化</p><p>webpack优化</p><p>代码优化</p><ol start="2"><li>发布-订阅设计模式</li><li>函数式编程</li></ol><p><strong>4. git的使用 [重要]</strong></p><ol start="5"><li>代码规范：eslint</li></ol><p><strong>非技术性面试</strong></p><ol><li>自我介绍</li><li>你的职业和技术规划？【 每家公司都会问 】</li><li>为什么学习前端而不是其他方向？【大概率会问 】</li><li>你是怎么学习前端的？</li><li>项目的重点和难点？【必问】</li><li>对于工作地点的考虑</li><li>对于我们公司你还有什么想问的嘛？</li></ol><p>-------------------------------</p><ol><li>实习经历</li><li>期望薪资</li><li>你的优缺点</li><li>offer情况</li></ol><p><strong>3. 如何准备面试</strong></p><ol><li>根据知识体系分模块、逐个解决</li></ol><p>校招前端面试通常就是 基础布局（html/css） + JS核心概念清楚 + 框架+ 一定的项目经验 + 计算机基础（主要是计算机网络和算法）。对于每一个知识点，你可以尝试进行自我回答，然后在掘金，知乎等平台上搜索对于这个知识点的详细解析（比如BFC、闭包这些难懂的概念），最终形成一个比较完善的回答。</p><ol start="2"><li>一定要记录（这里<strong>推荐语雀或者飞书的知识库</strong>，真的很好用）</li></ol><p>记录会形成一个进度条一样的东西（反馈很重要），比如说我前面提到的那些知识点，你可以打印出来（就几张纸），你可以学完一条，打个对勾，这样你就知道自己复习了什么，还有什么没学。</p><ol start="3"><li>对于不懂的知识点多看多复习</li></ol><p>有一些概念就是很容易忘记的，或者很难的，不然也不会有“js三座大山”的说法，对于这些比较难懂的知识点或者经常忘记的知识点（比如布局、手写），最好的办法就是多看多写。概念可以通过看不同的文章去帮助你理解概念，手写则是每几天写一遍（可以尝试白纸默写）</p><ol start="4"><li>积极面试</li></ol><p>以面带学，人吧有的时候会很自信，觉得自己对于某一个方面复习好了，很主动的说自己这个方面很了解，但面试官一往深里问，整个人都傻了，有的时候则是觉得自己啥都没准备好，这也不会，那也不会。不去面试是没有发言权的，不去面试一下你都不知道自己有多菜（🐶）。所以多去面试，对于面试结果不要过分在意，<strong>即便面的不好也要学会快速调整过来（你答的不好，隔着屏幕呢，面试官又不会吃了你，不行下一家呗，下一个福利更好，下一个待遇更高，下一个还965）</strong>，<strong>及时复盘</strong>，因为下一家可能问的东西是一样的。</p><ol start="5"><li>面试技巧</li></ol><p>讲概念：用一句话描述是什么</p><p>说用途：结合具体场景，说你的应用</p><p>理原理：梳理该技术是怎么实现的（根据自我能力回答吧）</p><p>优缺点：横向对比其他技术解决方案（可以作为引导面试官的重要手段）</p><p><strong>3. 前端学习资料分享</strong></p><blockquote><p>由于本人水平有限，内容只是讲到基础的应用层面，可能也只是能帮你应对前端八股文的一些内容，请多多包容。</p></blockquote><p>每个人的学习能力不同，有的喜欢看视频学习，有的觉得看视频比较浪费时间,习惯于看文档或者书籍，我尽量给出两种方式，仅供参考。但无论哪种学习方式，最核心的仍然是多动手，多动脑，多实践练习。(下面我提供的框架的视频有很多，都是讲的很好的老师，选择一个快速了解语法就可以）</p><p><strong>Javascript</strong></p><p>如果你现在时间很充裕，比如大一大二，并且喜欢看视频学习的话，那你完全可以花比较长的时间去学js,我个人比较推荐周啸天老师的js视频（神三元也推荐过），周老师把js的数据类型，闭包作用域，函数执行机制，面向对象，同步异步编程这些核心的概念讲的偏僻入里，另外coderwhy老师的js高级语法课也是不错的。</p><p>书籍的话，《JavaScript高级程序设计》第四版和阮一峰老师的ES6教程（有电子版）这两本书是必备的(初开始的时候不必全部啃完，可以先看我下面推荐的这本，等把一些重点概念搞清楚后再回来查漏补缺），除此之外我还推荐**《Javascript重难点实例精讲》**这本书（微信读书上有电子版），这本书把js一些核心内容捋了一遍（也是面试经常问的基础点），缺点是没有讲到同步异步这块。</p><p>至于大家经常说的“小黄书”《你不知道的javascript》，我个人是不推荐的，这套书只有第一本算是比较易读的，其他两本读起来就很困难，可以看浪里行舟或者伢羽的博客，作为小黄书的替代品，基本上是对小黄书的归纳</p><p>周啸天老师的js视频：</p><p><a href="https://www.bilibili.com/video/BV1rV411n72v?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1rV411n72v?share_source=copy_web</a></p><p><a href="https://www.bilibili.com/video/BV1cZ4y1F7ry?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1cZ4y1F7ry?share_source=copy_web</a></p><p>coderwhy老师的js课：我会把coderwhy老师的js/vue3/react/node/webpack视频课统一放在一个百度网盘里，链接放在文章最后（请录友们仅作学习使用）</p><p>阮一峰ES6教程</p><p><a href="https://es6.ruanyifeng.com/" target="_blank" rel="noreferrer">https://es6.ruanyifeng.com/</a></p><p>浪里行舟的博客</p><p><a href="https://github.com/ljianshu/Blog" target="_blank" rel="noreferrer">https://github.com/ljianshu/Blog</a></p><p>伢羽js全解析</p><p><a href="https://github.com/mqyqingfeng/Blog" target="_blank" rel="noreferrer">https://github.com/mqyqingfeng/Blog</a></p><p>---------------------------------------------------</p><p>现代javascript教程：<a href="https://zh.javascript.info/" target="_blank" rel="noreferrer">https://zh.javascript.info/</a></p><p><strong>Vue</strong></p><p>很多人入门vue应该看的是coderwhy（现在看有点过时了）或者尚硅谷张老师的vue课</p><p>尚硅谷：<a href="https://www.bilibili.com/video/BV1Zy4y1K7SH?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1Zy4y1K7SH?share_source=copy_web</a></p><p>coderwhy：<a href="https://www.bilibili.com/video/BV15741177Eh?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV15741177Eh?share_source=copy_web</a> (这个时间比较久了)</p><p>千锋：<a href="https://www.bilibili.com/video/BV1GL4y1v79M?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1GL4y1v79M?share_source=copy_web</a></p><p>-----------------</p><p>项目1</p><p><a href="https://www.bilibili.com/video/BV1Vf4y1T7bw?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1Vf4y1T7bw?share_source=copy_web</a></p><p>项目2</p><p><a href="https://space.bilibili.com/13625996/channel/seriesdetail?sid=291695" target="_blank" rel="noreferrer">https://space.bilibili.com/13625996/channel/seriesdetail?sid=291695</a></p><p>----------------------------------</p><p>Vue3 + Ts</p><p><a href="https://www.bilibili.com/video/BV1ra4y1H7ih?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1ra4y1H7ih?share_source=copy_web</a></p><p>coderwhy老师的视频课（放在结尾链接）</p><p>书籍的话没有合适的，感兴趣的可以看被删-深入理解Vue.js实战(godbasin.com)</p><p><img src="https://pqex9o8uut.feishu.cn/space/api/box/stream/download/asynccode/?code=MDQ3MGI4ZTUzMDZiYzE4YzE2YTFlYTdkYjY4MmJmMjZfUk5zRUI3WVcxUkw0S0xoaFN6UllJVldvTTk2VFhseXVfVG9rZW46Ym94Y25Td1ppdjBzWXRvWTZ0WktrY3ltME9QXzE2NTA1NTgzODU6MTY1MDU2MTk4NV9WNA" alt="img"></p><p><strong>算法</strong></p><p>算法嘛，跟着代码随想录就够了，面试前可以看一看CodeTop企业题库,上面汇集了一些大厂经常考的题目。</p><p>如果说你确实需要js版本的算法指南，下面三个可以作为参考</p><ol><li>awesome-coding-js,除了算法，还有一些比较常见的js手写代码题</li></ol><p><a href="http://www.conardli.top/docs" target="_blank" rel="noreferrer">http://www.conardli.top/docs/</a></p><ol start="2"><li>ssh的刷题指南</li></ol><p><a href="https://github.com/sl1673495/leetcode-javascript" target="_blank" rel="noreferrer">https://github.com/sl1673495/leetcode-javascript</a></p><ol start="3"><li>前端瓶子君的算法小书</li></ol><p><a href="https://www.pzijun.cn/algorithms" target="_blank" rel="noreferrer">https://www.pzijun.cn/algorithms/</a></p><p><img src="https://pqex9o8uut.feishu.cn/space/api/box/stream/download/asynccode/?code=ZDUyNjA0ZGQ5Yzg1YjllZTFhY2YyYThiODU5NGUwMDBfbE1VWDlmWkNZQ0tKek5GV1lWcnFEcjZOZzNPQ0p3ejBfVG9rZW46Ym94Y25sZmdEYVh1dWVKcUxmZktQaThHZXllXzE2NTA1NTgzODU6MTY1MDU2MTk4NV9WNA" alt="img"></p><p><strong>网络和浏览器</strong></p><p>大一大二学习网络可以看b站湖科大教书匠的计算机网络微课堂（学校考试也可以看）</p><p><a href="https://www.bilibili.com/video/BV1c4411d7jb?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1c4411d7jb?share_source=copy_web</a></p><p>着急面试的不推荐看视频，因为性价比较低，看书、博客背面试题是最快的方式，实在有看视频需求的可以看李明杰老师讲的网络协议课（b站链接失效了，放在下面网盘）</p><p>博客</p><p>​ 小林coding的图解计算机网络 <a href="https://xiaolincoding.com/network" target="_blank" rel="noreferrer">https://xiaolincoding.com/network/</a></p><p>极客时间专栏</p><ul><li><strong>浏览器工作原理与实践</strong></li><li>趣谈网络协议</li><li><strong>透视HTTP协议</strong></li><li>图解Google V8</li></ul><p><strong>Webpack</strong></p><p><a href="https://www.bilibili.com/video/BV1YU4y1g745?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1YU4y1g745?share_source=copy_web</a></p><p><strong>React</strong></p><p>张天禹： <a href="https://www.bilibili.com/video/BV1wy4y1D7JT?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1wy4y1D7JT?share_source=copy_web</a></p><p>kerwin: <a href="https://www.bilibili.com/video/BV1dP4y1c7qd?share_source=copy_web" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1dP4y1c7qd?share_source=copy_web</a></p><p><strong>八股文推荐</strong></p><ol><li>浪里行舟的博客已经在前面推荐过，是比较核心的要点，所以需要全都掌握</li><li>CUGGZ：（基本上包含了所有的八股文，很强，根据自己的能力看）</li></ol><p><a href="https://juejin.cn/post/6964779204462247950" target="_blank" rel="noreferrer">https://juejin.cn/post/6964779204462247950</a></p><ol start="3"><li>前端面试必读文章 （文章收集系列）</li></ol><p><a href="https://juejin.cn/post/6844904116339261447" target="_blank" rel="noreferrer">https://juejin.cn/post/6844904116339261447</a></p><ol start="4"><li>前端进阶之道（一些比较重要的知识点，还是比较推荐的）</li></ol><p><a href="https://yuchengkai.cn/" target="_blank" rel="noreferrer">https://yuchengkai.cn/</a></p><ol start="5"><li>前端复习课（给所有对应的考点提供了一个链接，相当于有参考答案，推荐，pdf在飞书文档中无法导出，放公众号链接了）</li></ol><p><a href="https://mp.weixin.qq.com/s/a-6ck3i6b5OLhEAgxRHkDA" target="_blank" rel="noreferrer">https://mp.weixin.qq.com/s/a-6ck3i6b5OLhEAgxRHkDA</a></p><p>最低要求：掌握浪里行舟的博客</p><p>进阶：前端复习课 + 前端进阶之道</p><p>全面：GUGGZ的面试题</p><p>coderwhy老师网课链接（仅仅做学习使用，请勿商业用途）</p><p>--来自百度网盘超级会员V5的分享</p><p>hi，这是我用百度网盘分享的内容~复制这段内容打开「百度网盘」APP即可获取</p><p>链接:<a href="https://pan.baidu.com/s/1Nv9uQLDTKEf72OaanDmziw" target="_blank" rel="noreferrer">https://pan.baidu.com/s/1Nv9uQLDTKEf72OaanDmziw</a></p><p>提取码:7w2m</p><div style="display:none;" data-pagefind-meta="base64:JTdCJTIyZGF0ZSUyMiUzQTE3MTUwNjMyMTQ2MzMlN0Q="></div>',270),s=[i];function e(n,a,g,c,h,b){return o(),r("div",null,s)}const m=t(p,[["render",e]]);export{d as __pageData,m as default};
